#include <iostream>

using namespace std;

void league(char *matches, int n) {
    int score = 0;
    int wins[n] = {0};
    int unplayed[n] = {0};

    for (int i = 0; i < n; ++i){
        for (int j = 0; j < n; ++j) {
            if (matches[i * n + j] == 1) {
                ++wins[i];
                if (score < wins[i]) score = wins[i];
            }
            else if (matches[i * n + j] == 2) ++unplayed[i];
        }
    }
    for (int i = 0; i < n; ++i) {
        if (wins[i] + unplayed[i] < score) continue;
        for (int j = 0; j < n; ++j)
            if (matches[i * n + j] == 2 && wins[i] == score && wins[j] == score) ++score;
    }

    for (int i = 0; i < n; ++i)
        if (wins[i] + unplayed[i] < score) cout << '0';
        else cout << '1';
    cout << '\n';
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int t, n;
    cin >> t;
    for (int i = 0; i < t; ++i) {
        cin >> n;
        char * matches = new char[n * n];
        for (int x = 0; x < n; ++x)
            for (int y = 0; y < n; ++y) {
                cin >> matches[x * n + y];
                matches[x * n + y] -= '0';
            }
        league(matches, n);
    }

    return 0;
}
